use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use std::fs;
use std::path::Path;

async fn serve_file(filename: web::Path<String>) -> impl Responder {
    let uploads_dir = "uploads/";
    let file_path = Path::new(uploads_dir).join(&filename);

    if file_path.starts_with(Path::new(uploads_dir)) && file_path.is_file() {
        match fs::read_to_string(file_path) {
            Ok(contents) => HttpResponse::Ok().body(contents),
            Err(_) => HttpResponse::NotFound().finish(),
        }
    } else {
        HttpResponse::Forbidden().finish()
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}